import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DashboardStats } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [loading, setLoading] = useState(true);
  const isStaff = user?.userType === 'user';

  useEffect(() => {
    api.get('/borrows/stats').then(r=>{setStats(r.data.data);setLoading(false);}).catch(()=>setLoading(false));
  }, []);

  if (loading) return (
    <div style={{display:'flex',alignItems:'center',justifyContent:'center',height:'100vh'}}>
      <div style={{width:36,height:36,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite'}}/>
    </div>
  );

  const cards = [
    { label:'Total Books',    value:stats?.totalBooks||0,    accent:'#6366f1', tag:'Library'  },
    { label:'Active Members', value:stats?.totalMembers||0,  accent:'#10b981', tag:'Enrolled' },
    { label:'Books Out',      value:stats?.activeBorrows||0, accent:'#c9a84c', tag:'Active'   },
    { label:'Overdue',        value:stats?.overdueBorrows||0,accent:'#ef4444', tag:'Urgent'   },
  ];

  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Good Morning' : hour < 17 ? 'Good Afternoon' : 'Good Evening';

  return (
    <div className="page-enter" style={{padding:'36px 40px', minHeight:'100vh', width:'100%'}}>
      <style>{`
        .scard { transition: all .22s !important; }
        .scard:hover { transform: translateY(-4px) !important; box-shadow: 0 20px 50px rgba(0,0,0,0.4) !important; }
        .al-btn { transition: all .2s !important; }
        .al-btn:hover { filter: brightness(1.1); }
        .lrow { transition: background .15s !important; border-radius: 12px; }
        .lrow:hover { background: rgba(255,255,255,0.04) !important; }
      `}</style>

      {/* ── Header ── */}
      <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:36,gap:20}}>
        <div>
          <p style={{fontSize:12,color:'rgba(255,255,255,0.22)',letterSpacing:'2px',textTransform:'uppercase',marginBottom:10,fontWeight:600}}>
            {new Date().toLocaleDateString('en-US',{weekday:'long',year:'numeric',month:'long',day:'numeric'})}
          </p>
          <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:36,fontWeight:700,color:'#fff',lineHeight:1.15,letterSpacing:'-0.5px'}}>
            {greeting}, {user?.name?.split(' ')[0]}
          </h1>
          <p style={{fontSize:14,color:'rgba(255,255,255,0.3)',marginTop:8,fontWeight:400}}>
            Welcome to the BAUST Library Management System
          </p>
        </div>
        <div style={{background:'rgba(201,168,76,0.07)',border:'1px solid rgba(201,168,76,0.15)',borderRadius:14,padding:'14px 20px',textAlign:'right',flexShrink:0}}>
          <div style={{fontSize:10,color:'rgba(255,255,255,0.22)',marginBottom:5,letterSpacing:'1.5px',textTransform:'uppercase',fontWeight:700}}>Signed in as</div>
          <div style={{fontSize:15,fontWeight:800,color:'#c9a84c'}}>
            {user?.role==='librarian'?'Head Librarian':user?.role==='library_assistant'?'Library Assistant':user?.role==='student'?'Student':'Staff Member'}
          </div>
          {user?.member_id && <div style={{fontSize:11,color:'rgba(255,255,255,0.25)',marginTop:4,fontFamily:'monospace'}}>ID: {user.member_id}</div>}
        </div>
      </div>

      {/* ── Alerts ── */}
      {isStaff && stats && stats.pendingMembers > 0 && (
        <div className="al-btn" onClick={()=>navigate('/members?status=pending')}
          style={{background:'rgba(245,158,11,0.07)',border:'1px solid rgba(245,158,11,0.18)',borderRadius:14,padding:'16px 22px',marginBottom:14,display:'flex',alignItems:'center',gap:16,cursor:'pointer'}}>
          <div style={{flex:1}}>
            <div style={{fontSize:15,fontWeight:700,color:'#fbbf24',marginBottom:2}}>{stats.pendingMembers} account(s) waiting for approval</div>
            <div style={{fontSize:13,color:'rgba(251,191,36,0.45)'}}>Click to review and approve members</div>
          </div>
          <span style={{fontSize:20,color:'rgba(251,191,36,0.4)'}}>→</span>
        </div>
      )}
      {isStaff && stats && stats.pendingRequests > 0 && (
        <div className="al-btn" onClick={()=>navigate('/requests')}
          style={{background:'rgba(99,102,241,0.07)',border:'1px solid rgba(99,102,241,0.18)',borderRadius:14,padding:'16px 22px',marginBottom:28,display:'flex',alignItems:'center',gap:16,cursor:'pointer'}}>
          <div style={{flex:1}}>
            <div style={{fontSize:15,fontWeight:700,color:'#a5b4fc',marginBottom:2}}>{stats.pendingRequests} borrow request(s) pending</div>
            <div style={{fontSize:13,color:'rgba(165,180,252,0.45)'}}>Click to review and approve requests</div>
          </div>
          <span style={{fontSize:20,color:'rgba(165,180,252,0.4)'}}>→</span>
        </div>
      )}

      {stats && (
        <>
          {/* ── Stat Cards ── */}
          <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:18,marginBottom:28}}>
            {cards.map(c=>(
              <div key={c.label} className="scard"
                style={{background:'#11112a',border:'1px solid rgba(255,255,255,0.07)',borderRadius:20,padding:'26px 24px 22px',position:'relative',overflow:'hidden'}}>
                <div style={{position:'absolute',top:-20,right:-20,width:110,height:110,background:c.accent+'18',borderRadius:'50%',filter:'blur(35px)',pointerEvents:'none'}}/>
                <div style={{display:'flex',justifyContent:'flex-end',marginBottom:20}}>
                  <span style={{fontSize:11,fontWeight:700,padding:'4px 13px',borderRadius:99,background:c.accent+'18',color:c.accent,letterSpacing:'.5px',border:`1px solid ${c.accent}28`}}>{c.tag}</span>
                </div>
                <div style={{fontFamily:"'Playfair Display',serif",fontSize:48,fontWeight:700,color:'#fff',lineHeight:1,marginBottom:8,letterSpacing:'-2px'}}>{c.value}</div>
                <div style={{fontSize:14,color:'rgba(255,255,255,0.35)',fontWeight:500,marginBottom:16}}>{c.label}</div>
                <div style={{height:3,background:'rgba(255,255,255,0.05)',borderRadius:99,overflow:'hidden'}}>
                  <div style={{height:'100%',width:c.value>0?'62%':'5%',background:`linear-gradient(90deg,${c.accent},${c.accent}55)`,borderRadius:99}}/>
                </div>
              </div>
            ))}
          </div>

          {/* ── Bottom Panels ── */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:20}}>
            {/* Recent Borrows */}
            <div style={{background:'#11112a',border:'1px solid rgba(255,255,255,0.07)',borderRadius:20,padding:26}}>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:22}}>
                <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:19,fontWeight:700,color:'#fff'}}>Recent Borrows</h3>
                <span style={{fontSize:11,color:'rgba(255,255,255,0.22)',background:'rgba(255,255,255,0.04)',border:'1px solid rgba(255,255,255,0.07)',padding:'4px 12px',borderRadius:99,fontWeight:600}}>Latest 5</span>
              </div>
              {stats.recentBorrows.length ? stats.recentBorrows.map((b:any)=>(
                <div key={b.id} className="lrow" style={{display:'flex',alignItems:'center',gap:14,padding:'12px 14px',marginBottom:4}}>
                  <div style={{width:8,height:8,borderRadius:'50%',flexShrink:0,
                    background:b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24',
                    boxShadow:`0 0 8px ${b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24'}88`}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:14,fontWeight:600,color:'#fff',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:12,color:'rgba(255,255,255,0.28)',marginTop:2}}>{b.member_name} · <span style={{textTransform:'capitalize'}}>{b.account_type}</span></div>
                  </div>
                  <span style={{fontSize:11,fontWeight:700,padding:'4px 11px',borderRadius:99,flexShrink:0,textTransform:'capitalize',
                    background:b.status==='returned'?'rgba(52,211,153,0.1)':b.status==='overdue'?'rgba(248,113,113,0.1)':'rgba(251,191,36,0.1)',
                    color:b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24'
                  }}>{b.status}</span>
                </div>
              )) : (
                <div style={{textAlign:'center',padding:'36px 0',color:'rgba(255,255,255,0.18)',fontSize:14,fontStyle:'italic'}}>No borrows yet</div>
              )}
            </div>

            {/* Popular Books */}
            <div style={{background:'#11112a',border:'1px solid rgba(255,255,255,0.07)',borderRadius:20,padding:26}}>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:22}}>
                <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:19,fontWeight:700,color:'#fff'}}>Popular Books</h3>
                <span style={{fontSize:11,color:'rgba(255,255,255,0.22)',background:'rgba(255,255,255,0.04)',border:'1px solid rgba(255,255,255,0.07)',padding:'4px 12px',borderRadius:99,fontWeight:600}}>Top 5</span>
              </div>
              {stats.popularBooks.length ? stats.popularBooks.map((b:any,i:number)=>(
                <div key={b.title} className="lrow" style={{display:'flex',alignItems:'center',gap:14,padding:'12px 14px',marginBottom:4}}>
                  <div style={{width:28,height:28,borderRadius:8,flexShrink:0,display:'flex',alignItems:'center',justifyContent:'center',fontSize:13,fontWeight:800,
                    background:i===0?'linear-gradient(135deg,#c9a84c,#a87d30)':i===1?'rgba(148,163,184,0.12)':i===2?'rgba(180,100,60,0.12)':'rgba(255,255,255,0.04)',
                    color:i===0?'#1a1a2e':i===1?'#94a3b8':i===2?'#b47844':'rgba(255,255,255,0.25)',
                    boxShadow:i===0?'0 4px 14px rgba(201,168,76,0.4)':'none'
                  }}>{i+1}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:14,fontWeight:600,color:'#fff',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:12,color:'rgba(255,255,255,0.28)',marginTop:2}}>{b.author}</div>
                  </div>
                  <div style={{fontSize:15,fontWeight:800,color:'#c9a84c',flexShrink:0}}>{b.borrow_count}×</div>
                </div>
              )) : (
                <div style={{textAlign:'center',padding:'36px 0',color:'rgba(255,255,255,0.18)',fontSize:14,fontStyle:'italic'}}>No data yet</div>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
}
